122	// LoadPackageManifestWithFallback reads package.yaml and falls back to the
123	// provided package when the manifest is missing.
124	func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
125		pkg, issues, err := LoadPackageManifest(root)
126		if err == nil {
127			// Return issues separately even when package is valid, so callers can
128			// detect schema problems while still using the package for structural audits.
129			if len(issues) > 0 {
130				return pkg, false, issues, nil
131			}
132			return pkg, false, nil, nil
133		}
134	
135		// If a partial package was returned (YAML parsed but validation issues exist),
136		// return it with the issues so callers can still use its structure.
137		if pkg != nil {
138			return pkg, false, issues, nil
139		}
140	
141		if os.IsNotExist(err) {
142			return fallback, true, nil, err
143		}
144	
145		if fallback != nil {
146			return fallback, false, issues, err
147		}
148		return nil, false, issues, err
149	}
150	
151	// validatePackageManifest validates required fields and returns a partial package
152	// even when validation issues are found. This ensures that structural audits
153	// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
154	func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
155		var issues []ValidationIssue
156	
157		name := strings.TrimSpace(raw.Name)
158		if name == "" {
159			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
160		}
161		version := strings.TrimSpace(raw.Version)
162		if version == "" {
163			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
164		}
165		description := strings.TrimSpace(raw.Description)
166		if description == "" {
167			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
168		}
169		pkgType, ok := parseManifestPackageType(raw.Type)
170		if !ok {
171			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
172		}
173		source := strings.TrimSpace(raw.Source)
174		if source == "" {
175			issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
176		}
177	
178		apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
179		if apiIssue != "" {
180			issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
181		}
182	
183		// Always construct a partial package so structural audits can proceed.
184		// Validation issues are still collected and returned separately.
185		pkg := &Package{
186			Name:        name,
187			Version:     version,
188			Description: description,
189			Type:        pkgType,
190			Source:      source,
191			APIVersion:  apiVersion,
192			Install:     raw.Install,
193			Keywords:    append([]string(nil), raw.Keywords...),
194		}
195		return pkg, issues
196	}
197	
198	func parseManifestPackageType(rawType string) (PackageType, bool) {
199		switch PackageType(strings.TrimSpace(rawType)) {
200		case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
201			return PackageType(strings.TrimSpace(rawType)), true
202		default:
203			return "", false
204		}
205	}
206	
207	func parseAPIVersion(raw any) (string, string) {
208		if raw == nil {
209			return "", "missing required field `api_version`"
210		}
211	
212		value := strings.TrimSpace(fmt.Sprint(raw))
213		if value == "" {
214			return "", "missing required field `api_version`"
215		}
216		if value != SupportedPackageAPIVersion {
217			return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
218		}
219		return value, ""
220	}
221	
222	// JoinValidationIssues renders a slice of validation issues into a single
223	// semicolon-separated error string.
224	func JoinValidationIssues(issues []ValidationIssue) string {
225		msgs := make([]string, 0, len(issues))
226		for _, issue := range issues {
227			msgs = append(msgs, issue.Error())
228		}
229		return strings.Join(msgs, "; ")
230	}
