601	func (f *CommandFactory) newAgentDoctorCommand() *cobra.Command {
602		cmd := &cobra.Command{
603			Use:          "doctor",
604			Short:        "Check agent harness health",
605			Args:         cobra.NoArgs,
606			SilenceUsage: true,
607			RunE: func(cmd *cobra.Command, args []string) error {
608				checkConnectivity, _ := cmd.Flags().GetBool("connectivity")
609				checkRouting, _ := cmd.Flags().GetBool("routing")
610				checkWorkers, _ := cmd.Flags().GetBool("workers")
611				timeoutStr, _ := cmd.Flags().GetString("timeout")
612				asJSON, _ := cmd.Flags().GetBool("json")
613	
614				// ADR-022 step 6: --workers prints the runtime worker registry
615				// (server-first, .ddx/workers/ on-disk fallback).
616				if checkWorkers {
617					return f.runAgentDoctorWorkers(cmd, f.WorkingDir, asJSON)
618				}
619	
620				// Parse timeout (default 15s for connectivity checks)
621				probeTimeout := 15 * time.Second
622				if timeoutStr != "" {
623					if t, err := time.ParseDuration(timeoutStr); err == nil {
624						probeTimeout = t
625					}
626				}
627	
628				// Routing mode: derive full routing state per harness via service.
629				if checkRouting {
630					svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
631					if svcErr != nil {
632						return fmt.Errorf("agent doctor: failed to initialize service: %w", svcErr)
633					}
634					ctx := cmd.Context()
635					harnesses, listErr := svc.ListHarnesses(ctx)
636					if listErr != nil {
637						return fmt.Errorf("agent doctor: listing harnesses: %w", listErr)
638					}
639	
640					// Refresh quota caches via HealthCheck, then re-fetch harness list.
641					for _, h := range harnesses {
642						_ = svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: h.Name})
643					}
644					harnesses, listErr = svc.ListHarnesses(ctx)
645					if listErr != nil {
646						return fmt.Errorf("agent doctor: re-listing harnesses after health check: %w", listErr)
647					}
648	
649					type routingState struct {
650						Installed     bool                         `json:"installed"`
651						Reachable     bool                         `json:"reachable"`
652						Authenticated bool                         `json:"authenticated"`
653						QuotaOK       bool                         `json:"quota_ok"`
654						QuotaState    string                       `json:"quota_state,omitempty"`
655						Degraded      bool                         `json:"degraded"`
656						Error         string                       `json:"error,omitempty"`
657						Quota         *agent.QuotaInfo             `json:"quota,omitempty"`
658						RoutingSignal *agent.RoutingSignalSnapshot `json:"routing_signal,omitempty"`
659						LastChecked   time.Time                    `json:"last_checked,omitempty"`
660					}
661					type routingEntry struct {
662						Name  string       `json:"name"`
663						State routingState `json:"state"`
664					}
665					now := time.Now()
666					var entries []routingEntry
667					for _, hi := range harnesses {
668						st := routingState{
669							Installed:   hi.Available,
670							LastChecked: now,
671						}
672						// Derive reachable/authenticated: HealthCheck already ran; available == reachable for harnesses.
673						st.Reachable = hi.Available
674						st.Authenticated = hi.Available
675						st.QuotaOK = true
676						// Derive quota state from upstream HarnessInfo.Quota.
677						if hi.Quota != nil {
678							switch hi.Quota.Status {
679							case "ok":
680								st.QuotaState = "ok"
681							case "stale":
682								st.QuotaState = "ok"
683							}
684							if len(hi.Quota.Windows) > 0 {
685								// Report worst window as current quota for routing.
686								var worstPct int
687								var worstReset string
688								blocked := false
689								for _, w := range hi.Quota.Windows {
690									if w.LimitID == "extra" {
691										continue
692									}
693									if w.State == "blocked" {
694										blocked = true
695										worstReset = w.ResetsAt
696									}
697									if int(w.UsedPercent+0.5) > worstPct {
698										worstPct = int(w.UsedPercent + 0.5)
699									}
700								}
701								if blocked {
702									st.QuotaState = "blocked"
703									st.QuotaOK = false
704								}
705								if worstPct > 0 && st.Quota == nil {
706									st.Quota = &agent.QuotaInfo{
707										PercentUsed: worstPct,
708										ResetDate:   worstReset,
709									}
710								}
711							}
712							// Translate upstream HarnessInfo into the local
713							// RoutingSignalSnapshot shape so the --json consumers
714							// (and human text below) keep their existing shape.
715							signal := harnessInfoToRoutingSignal(hi, now)
716							if signal.Provider != "" {
717								st.RoutingSignal = &signal
718							}
719						}
720						if st.QuotaState == "" {
721							st.QuotaState = "unknown"
722						}
723						if hi.Error != "" {
724							st.Error = hi.Error
725						}
726						entries = append(entries, routingEntry{Name: hi.Name, State: st})
727					}
728					if asJSON {
729						enc := json.NewEncoder(cmd.OutOrStdout())
730						enc.SetIndent("", "  ")
731						return enc.Encode(entries)
732					}
733					for _, e := range entries {
734						st := e.State
735						indicator := "ok"
736						if !st.Installed {
737							indicator = "not installed"
738						} else if !st.Reachable {
739							indicator = "not reachable"
740						} else if !st.Authenticated {
741							indicator = "not authenticated"
742						} else if st.QuotaState == "blocked" || (!st.QuotaOK && st.QuotaState != "unknown") {
743							indicator = "quota exceeded"
744						} else if st.Degraded {
745							indicator = "degraded"
746						} else if st.QuotaState == "unknown" {
747							indicator = "quota unknown"
748						}
749						quotaState := st.QuotaState
750						if quotaState == "" {
751							if st.QuotaOK {
752								quotaState = "ok"
753							} else {
754								quotaState = "blocked"
755							}
756						}
757						line := fmt.Sprintf("%-12s  installed=%-5v  reachable=%-5v  auth=%-5v  quota=%-8s  [%s]",
758							e.Name, st.Installed, st.Reachable, st.Authenticated, quotaState, indicator)
759						if st.Quota != nil {
760							quota := st.Quota
761							if quota.ResetDate != "" {
762								line += fmt.Sprintf("  quota: %d%% of %s (resets %s)", quota.PercentUsed, quota.LimitWindow, quota.ResetDate)
763							} else {
764								line += fmt.Sprintf("  quota: %d%% of %s", quota.PercentUsed, quota.LimitWindow)
765							}
766						}
767						if st.RoutingSignal != nil {
768							signal := st.RoutingSignal
769							if signal.Source.Kind != "" {
770								line += fmt.Sprintf("  source: %s/%s", signal.Source.Provider, signal.Source.Kind)
771							} else if signal.Source.Provider != "" {
772								line += fmt.Sprintf("  source: %s", signal.Source.Provider)
773							}
774							if signal.Source.Freshness != "" {
775								line += fmt.Sprintf("  freshness: %s", signal.Source.Freshness)
776							}
777							if signal.HistoricalUsage.TotalTokens > 0 {
778								line += fmt.Sprintf("  native-usage: %d tokens", signal.HistoricalUsage.TotalTokens)
779							}
780						}
781						if !st.LastChecked.IsZero() {
782							line += fmt.Sprintf("  checked: %s", st.LastChecked.UTC().Format(time.RFC3339))
783						}
784						if st.Error != "" {
785							line += "  error: " + st.Error
786						}
787						fmt.Fprintln(cmd.OutOrStdout(), line)
788						// Print non-session quota windows (weekly, extra, credit) as sub-lines.
789						if st.RoutingSignal != nil {
790							for _, w := range st.RoutingSignal.QuotaWindows {
791								if w.LimitID == "session" {
792									continue
793								}
794								wline := fmt.Sprintf("  %-10s  %-32s  %3.0f%%  state=%-8s", w.LimitID, w.Name, w.UsedPercent, w.State)
795								if w.ResetsAt != "" {
796									wline += "  resets: " + w.ResetsAt
797								}
798								fmt.Fprintln(cmd.OutOrStdout(), wline)
799							}
800						}
801					}
802					return nil
803				}
