805				svc, err := agent.NewServiceFromWorkDir(f.WorkingDir)
806				if err != nil {
807					return fmt.Errorf("constructing agent service: %w", err)
808				}
809				harnesses, err := svc.ListHarnesses(cmd.Context())
810				if err != nil {
811					return fmt.Errorf("listing harnesses: %w", err)
812				}
813				available := 0
814				functional := 0
815				for _, hi := range harnesses {
816					statusStr := "NOT FOUND"
817					if hi.Available {
818						available++
819						statusStr = fmt.Sprintf("OK (%s)", hi.Path)
820	
821						// Optionally test provider connectivity
822						if checkConnectivity {
823							providerStatus := agent.TestProviderConnectivityViaService(cmd.Context(), f.WorkingDir, hi.Name, probeTimeout)
824							if providerStatus.Reachable && providerStatus.CreditsOK {
825								statusStr = fmt.Sprintf("OK (%s) ✓ provider reachable", hi.Path)
826								functional++
827							} else if providerStatus.Reachable && !providerStatus.CreditsOK {
828								statusStr = fmt.Sprintf("⚠️  (%s) provider out of credits/quota", hi.Path)
829							} else if providerStatus.Error != "" {
830								statusStr = fmt.Sprintf("⚠️  (%s) %s", hi.Path, providerStatus.Error)
831							}
832						}
833					}
834					fmt.Fprintf(cmd.OutOrStdout(), "%-12s %s\n", hi.Name, statusStr)
835				}
836	
837				fmt.Fprintf(cmd.OutOrStdout(), "\n%d/%d harnesses available", available, len(harnesses))
838				if checkConnectivity && available > 0 {
839					fmt.Fprintf(cmd.OutOrStdout(), " (%d functional)", functional)
840				}
841				fmt.Fprintln(cmd.OutOrStdout())
842	
843				if available == 0 {
844					fmt.Fprintln(cmd.OutOrStdout(), "\n⚠️  No agent harnesses found.")
845					fmt.Fprintln(cmd.OutOrStdout(), "💡 Install codex, claude, or another supported agent.")
846					return nil
847				}
848				return nil
849			},
850		}
851		cmd.Flags().Bool("connectivity", false, "Test provider connectivity and credit status")
852		cmd.Flags().Bool("routing", false, "Probe and report full routing-relevant harness state (installed/reachable/auth/quota/degraded)")
853		cmd.Flags().Bool("workers", false, "Show runtime worker registry (server-first; .ddx/workers/ fallback)")
854		cmd.Flags().String("timeout", "", "Timeout for connectivity checks (default 15s)")
855		cmd.Flags().Bool("json", false, "Output as JSON (with --routing or --workers)")
856		return cmd
