862	// quota.Status values ("ok|stale|unavailable") map to the existing
863	// freshness vocabulary so the JSON output for `ddx agent doctor --routing`
864	// keeps its previous field layout.
865	func harnessInfoToRoutingSignal(info agentlib.HarnessInfo, now time.Time) agent.RoutingSignalSnapshot {
866		if info.Quota == nil && len(info.UsageWindows) == 0 && info.Account == nil {
