873				Email:    info.Account.Email,
874				PlanType: info.Account.PlanType,
875				OrgName:  info.Account.OrgName,
876			}
877		}
878	
879		if info.Quota != nil {
880			freshness := "fresh"
881			if !info.Quota.Fresh {
