883			}
884			if info.Quota.Status == "unavailable" || info.Quota.Status == "unauthenticated" {
885				freshness = "unknown"
886			}
887			kind := agent.NormalizeSignalSourceKind(info.Quota.Source)
888			var ageSeconds int64
