127	func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
128		if commitSHA == "" {
129			return "", nil
130		}
131	
132		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
133		defer cancel()
134	
135		repoDir := f.WorkingDir
136		if repoDir == "" {
137			repoDir = "."
138		}
139	
140		if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
141			return commitSHA, nil
142		}
143	
144		cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
145		out, err := cmd.Output()
146		if err != nil {
147			return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
148		}
149		return strings.TrimSpace(string(out)), nil
150	}
151	
152	func isFullCommitSHA(commitSHA string) bool {
153		if len(commitSHA) != 40 {
154			return false
155		}
156		for i := 0; i < len(commitSHA); i++ {
157			c := commitSHA[i]
158			if c >= '0' && c <= '9' {
159				continue
160			}
161			if c >= 'a' && c <= 'f' {
162				continue
163			}
164			if c >= 'A' && c <= 'F' {
165				continue
166			}
167			return false
168		}
169		return true
170	}
171	
172	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
173		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
174		if err != nil {
175			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
176		}
177		if normalizedCommitSHA == "" {
178			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
179		}
180		return normalizedCommitSHA, nil
181	}
