183	// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
184	// only bead tracker state. Closing provenance is suppressed only for pure
185	// tracker backfills that touch .ddx/beads.jsonl and nothing else.
186	func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
187		if commitSHA == "" {
188			return false
189		}
190	
191		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
192		defer cancel()
193	
194		cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
195		out, err := cmd.Output()
196		if err != nil {
197			return false
198		}
199	
200		for _, line := range strings.Split(string(out), "\n") {
201			path := strings.TrimSpace(line)
202			if path == "" {
203				continue
204			}
205			if path != ".ddx/beads.jsonl" {
206				return false
207			}
208		}
209	
210		return true
211	}
