227		dir := os.Getenv("DDX_BEAD_DIR")
228		if dir != "" {
229			if filepath.Base(dir) == ".ddx" {
230				if !filepath.IsAbs(dir) && f.WorkingDir != "" {
231					if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
232						return workspaceRoot
233					}
234					dir = filepath.Join(f.WorkingDir, dir)
235				}
236				return filepath.Dir(dir)
237			}
238			if !filepath.IsAbs(dir) && f.WorkingDir != "" {
239				return filepath.Join(f.WorkingDir, dir)
240			}
241			return dir
242		}
243		if f.WorkingDir == "" {
244			return ""
245		}
246		if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
247			return workspaceRoot
248		}
249		return f.WorkingDir
250	}
