492				if err := f.checkLifecycleMigrationGate(cmd); err != nil {
493					return err
494				}
495				s := f.beadStore()
496	
497				// --claim and --unclaim use dedicated store methods
498				if claim, _ := cmd.Flags().GetBool("claim"); claim {
499					assignee, _ := cmd.Flags().GetString("assignee")
500					if assignee == "" {
501						assignee = resolveClaimAssignee()
502					}
503					if err := s.Claim(args[0], assignee); err != nil {
504						return err
505					}
506					if _, err := f.beadAutoCommit("claim " + args[0]); err != nil {
507						return err
508					}
509					return nil
510				}
511				if unclaim, _ := cmd.Flags().GetBool("unclaim"); unclaim {
512					if err := s.Unclaim(args[0]); err != nil {
513						return err
514					}
515					if _, err := f.beadAutoCommit("unclaim " + args[0]); err != nil {
516						return err
517					}
518					return nil
519				}
520	
521				if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
522					for _, key := range unsetFlags {
523						if isProtectedBeadExtraKey(key) {
524							return fmt.Errorf("cannot unset protected bead field: %s", key)
525						}
526					}
527				}
528	
529				var setFlags []string
530				if rawSetFlags, _ := cmd.Flags().GetStringArray("set"); len(rawSetFlags) > 0 {
531					setFlags = make([]string, 0, len(rawSetFlags))
532					for _, kv := range rawSetFlags {
533						k, v, ok := strings.Cut(kv, "=")
534						if !ok {
535							return fmt.Errorf("--set requires key=value format, got: %s", kv)
536						}
537						if k == "closing_commit_sha" {
538							normalizedCommitSHA, err := f.resolveClosingCommitSHA(v)
539							if err != nil {
540								return err
541							}
542							v = normalizedCommitSHA
543						}
544						setFlags = append(setFlags, k+"="+v)
545					}
546				}
547	
548				statusValue, _ := cmd.Flags().GetString("status")
549				statusChanged := cmd.Flags().Changed("status")
550				statusOpts := beadTransitionOptionsFromSetFlags(statusValue, setFlags, "ddx bead update")
551	
552				applyUpdateFields := func(b *bead.Bead) error {
553					if v, _ := cmd.Flags().GetString("title"); cmd.Flags().Changed("title") {
554						b.Title = v
555					}
556					if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
557						b.Priority = v
558					}
559					if v, _ := cmd.Flags().GetString("labels"); cmd.Flags().Changed("labels") {
560						if v == "" {
561							b.Labels = []string{}
562						} else {
563							b.Labels = strings.Split(v, ",")
564						}
565					}
566					if v, _ := cmd.Flags().GetString("acceptance"); cmd.Flags().Changed("acceptance") {
567						b.Acceptance = v
568					}
569					if v, _ := cmd.Flags().GetString("assignee"); cmd.Flags().Changed("assignee") {
570						b.Owner = v
571					}
572					if v, _ := cmd.Flags().GetString("parent"); cmd.Flags().Changed("parent") {
573						b.Parent = v
574					}
575					if v, _ := cmd.Flags().GetString("description"); cmd.Flags().Changed("description") {
576						b.Description = v
577					}
578					if v, _ := cmd.Flags().GetString("notes"); cmd.Flags().Changed("notes") {
579						b.Notes = v
580					}
581					if len(setFlags) > 0 {
582						if b.Extra == nil {
583							b.Extra = make(map[string]any)
584						}
585						for _, kv := range setFlags {
586							k, v, ok := strings.Cut(kv, "=")
587							if !ok {
588								continue
589							}
590							// Route known field names to struct fields
591							switch k {
592							case "parent":
593								b.Parent = v
594							case "description":
595								b.Description = v
596							case "notes":
597								b.Notes = v
598							case "acceptance":
599								b.Acceptance = v
600							case "issue_type":
601								b.IssueType = v
602							default:
603								// Parse booleans and numbers for proper typing
604								switch v {
605								case "true":
606									b.Extra[k] = true
607								case "false":
608									b.Extra[k] = false
609								default:
610									b.Extra[k] = v
611								}
612							}
613						}
614					}
615					if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
616						for _, key := range unsetFlags {
617							if b.Extra != nil {
618								delete(b.Extra, key)
619							}
620						}
621					}
622					return nil
623				}
624	
625				var err error
626				if statusChanged {
627					err = s.UpdateWithLifecycleStatus(args[0], statusValue, statusOpts, applyUpdateFields)
628				} else {
629					err = s.Update(args[0], func(b *bead.Bead) {
630						_ = applyUpdateFields(b)
631					})
632				}
633				if err != nil {
634					return err
635				}
636				if _, err := f.beadAutoCommit("update " + args[0]); err != nil {
637					return err
638				}
639				return nil
640			},
641		}
642	
643		cmd.Flags().String("title", "", "New title")
644		cmd.Flags().String("status", "", "New lifecycle status (validated transition)")
645		cmd.Flags().Int("priority", 0, "New priority")
646		cmd.Flags().String("labels", "", "New labels (comma-separated)")
647		cmd.Flags().String("acceptance", "", "New acceptance criteria")
648		cmd.Flags().String("assignee", "", "New assignee or claim assignee fallback")
649		cmd.Flags().String("parent", "", "New parent bead ID")
650		cmd.Flags().String("description", "", "New description")
651		cmd.Flags().String("notes", "", "New notes")
652		cmd.Flags().Bool("claim", false, "Claim: set status=in_progress, assignee=ddx")
653		cmd.Flags().Bool("unclaim", false, "Unclaim: set status=open, clear assignee and claim fields")
654		cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")
