678	// beadHasLegacyLifecycleInputs detects beads that require lifecycle migration
679	// before they can be executed. Migration-only: these status values and labels
680	// are legacy; new rows use canonical statuses and the lifecycle state machine.
681	func beadHasLegacyLifecycleInputs(b bead.Bead) bool {
682		if b.Status == "needs_investigation" || b.Status == "needs_human" {
683			return true
684		}
685		for _, label := range b.Labels {
686			if label == bead.LabelNeedsHuman || label == bead.LabelNeedsInvestigation {
687				return true
688			}
689		}
690		return false
691	}
