693	func beadTransitionOptionsFromSetFlags(status string, setFlags []string, source string) bead.LifecycleTransitionOptions {
694		opts := bead.LifecycleTransitionOptions{
695			Reason: "set lifecycle status",
696			Source: source,
697		}
698		if status == bead.StatusBlocked {
699			for _, kv := range setFlags {
700				k, v, ok := strings.Cut(kv, "=")
701				if ok && k == bead.ExtraLifecycleExternalBlockerReason {
702					opts.ExternalBlockerReason = v
703					break
704				}
705			}
706		}
707		return opts
708	}
