783	func (f *CommandFactory) newBeadCloseCommand() *cobra.Command {
784		cmd := &cobra.Command{
785			Use:   "close <id>",
786			Short: "Close a bead",
787			Args:  cobra.ExactArgs(1),
788			RunE: func(cmd *cobra.Command, args []string) error {
789				if err := f.checkLifecycleMigrationGate(cmd); err != nil {
790					return err
791				}
792				s := f.beadStore()
793				sessionID, _ := cmd.Flags().GetString("session")
794				commitSHA, _ := cmd.Flags().GetString("commit")
795	
796				if commitSHA != "" {
797					normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
798					if err != nil {
799						return err
800					}
801					commitSHA = normalizedCommitSHA
802				}
803	
804				target, err := s.Get(args[0])
805				if err != nil {
806					return err
807				}
808				// CloseWithEvidence runs the closure gate (ddx-e30e60a9); manual
809				// operator closes without evidence are intentionally a separate
810				// path. When --session and --commit are both unset, we are in
811				// manual-administration territory — use the ungated Store.Close
812				// so the gate doesn't reject legitimate tracker admin.
813				if sessionID == "" && commitSHA == "" {
814					if err := s.Close(args[0]); err != nil {
815						return err
816					}
817				} else if err := s.CloseWithEvidence(args[0], sessionID, commitSHA); err != nil {
818					return err
819				}
820	
821				landedSHA, err := f.beadAutoCommitIncludingStaged("close " + args[0])
822				if err != nil {
823					return err
824				}
825				if commitSHA == "" && landedSHA != "" {
826					if f.commitIsMetadataOnlyTrackerBackfill(landedSHA) {
827						if isReviewCloseBead(target) {
828							// Tracker-only review-finding closes must not retain any prior
829							// replay boundary. The close commit itself is the metadata-only
830							// backfill, so clear stale closing provenance instead of
831							// preserving an unrelated implementation SHA.
832							if err := s.Update(args[0], func(b *bead.Bead) {
833								if b.Extra == nil {
834									return
835								}
836								delete(b.Extra, "closing_commit_sha")
837							}); err != nil {
838								return err
839							}
840							followupSHA, err := f.beadAutoCommit("close " + args[0])
841							if err != nil {
842								return err
843							}
844							if followupSHA == "" {
845								return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
846							}
847						}
848					} else {
849						// Only stamp closing provenance when the close commit includes
850						// real implementation work. Pure tracker backfills should not
851						// advertise a replay boundary that points at metadata-only
852						// provenance.
853						if err := s.Update(args[0], func(b *bead.Bead) {
854							if b.Extra == nil {
855								b.Extra = make(map[string]any)
856							}
857							b.Extra["closing_commit_sha"] = landedSHA
858						}); err != nil {
859							return err
860						}
861						followupSHA, err := f.beadAutoCommit("close " + args[0])
862						if err != nil {
863							return err
864						}
865						if followupSHA == "" {
866							return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
867						}
868					}
869				}
870				return nil
871			},
872		}
873		cmd.Flags().String("session", "", "Agent session ID that completed this bead")
874		cmd.Flags().String("commit", "", "Closing commit SHA (auto-detected if not provided)")
875		return cmd
876	}
