1114	func (f *CommandFactory) resolveNeedsHumanBead(id, action, note string, children []string) error {
1115		action = strings.TrimSpace(action)
1116		note = strings.TrimSpace(note)
1117		if note == "" {
1118			return fmt.Errorf("--note is required")
1119		}
1120		s := f.beadStore()
1121		switch action {
1122		case "retry":
1123			if err := s.UpdateWithLifecycleStatus(id, bead.StatusOpen, bead.LifecycleTransitionOptions{
1124				Reason: "human resolve retry",
1125				Actor:  resolveClaimAssignee(),
1126				Source: "ddx bead human resolve",
1127			}, func(b *bead.Bead) error {
1128				// Migration-only cleanup: removes LabelNeedsHuman from legacy rows;
1129				// new rows carry status=proposed rather than this label.
1130				removeBeadLabel(b, bead.LabelNeedsHuman)
1131				bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
1132				return nil
1133			}); err != nil {
1134				return err
1135			}
1136			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1137				return err
1138			}
1139		case "split":
1140			children = normalizeChildIDs(children)
1141			if len(children) == 0 {
1142				return fmt.Errorf("--children is required when --action split")
1143			}
1144			if err := validateSplitChildren(s, id, children); err != nil {
1145				return err
1146			}
1147			for _, childID := range children {
1148				if err := s.DepAdd(id, childID); err != nil {
1149					return err
1150				}
1151			}
1152			if err := s.UpdateWithLifecycleStatus(id, bead.StatusOpen, bead.LifecycleTransitionOptions{
1153				Reason: "human resolve split",
1154				Actor:  resolveClaimAssignee(),
1155				Source: "ddx bead human resolve",
1156			}, func(b *bead.Bead) error {
1157				// Migration-only cleanup: removes LabelNeedsHuman from legacy rows;
1158				// new rows carry status=proposed rather than this label.
1159				removeBeadLabel(b, bead.LabelNeedsHuman)
1160				bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{})
1161				return nil
1162			}); err != nil {
1163				return err
1164			}
1165			if err := appendNeedsHumanResolutionEvent(s, id, action, note, children); err != nil {
1166				return err
1167			}
1168		case "obsolete":
1169			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1170				return err
1171			}
1172			if err := s.Close(id); err != nil {
1173				return err
1174			}
1175		case "defer":
1176			if err := appendNeedsHumanResolutionEvent(s, id, action, note, nil); err != nil {
1177				return err
1178			}
1179		default:
1180			return fmt.Errorf("unknown --action %q (valid: retry, split, obsolete, defer)", action)
1181		}
1182		if _, err := f.beadAutoCommit("human resolve " + id); err != nil {
1183			return err
1184		}
1185		return nil
1186	}
