1230	func normalizeChildIDs(children []string) []string {
1231		var out []string
1232		seen := map[string]bool{}
1233		for _, raw := range children {
1234			for _, part := range strings.Split(raw, ",") {
1235				child := strings.TrimSpace(part)
1236				if child == "" || seen[child] {
1237					continue
1238				}
1239				seen[child] = true
1240				out = append(out, child)
1241			}
1242		}
1243		return out
1244	}
