1250		for _, childID := range children {
1251			if childID == parentID {
1252				return fmt.Errorf("split child cannot be the parent bead: %s", childID)
1253			}
1254			if _, err := s.Get(childID); err != nil {
1255				return fmt.Errorf("split child %s: %w", childID, err)
1256			}
1257		}
1258		return nil
1259	}
