1533	func (f *CommandFactory) newBeadMergeCommand() *cobra.Command {
1534		cmd := &cobra.Command{
1535			Use:   "merge [path]",
1536			Short: "Resolve a Git conflict in .ddx/beads.jsonl",
1537			Long: `Resolve a Git conflict in .ddx/beads.jsonl using DDx tracker rules.
1538	
1539	This is the supported escape hatch when Git leaves the bead tracker in an
1540	unmerged state. It reads the base, ours, and theirs versions from the Git
1541	index stages (:1:, :2:, :3:), merges records by bead id, preserves append-only
1542	events and dependency edges, writes the resolved JSONL file, and reports any
1543	scalar fields that required deterministic conflict resolution.
1544	
1545	This command is not a general hand-edit workflow for bead tracker data.`,
1546			Args: cobra.MaximumNArgs(1),
1547			RunE: func(cmd *cobra.Command, args []string) error {
1548				path := filepath.Join(".ddx", "beads.jsonl")
1549				if len(args) > 0 {
1550					path = args[0]
1551				}
1552				workspaceRoot := f.beadWorkspaceRoot()
1553				if workspaceRoot == "" {
1554					workspaceRoot = f.WorkingDir
1555				}
1556				repoRoot := gitpkg.FindProjectRoot(workspaceRoot)
1557				relPath, err := filepath.Rel(repoRoot, filepath.Join(workspaceRoot, path))
1558				if err != nil || strings.HasPrefix(relPath, ".."+string(filepath.Separator)) || relPath == ".." {
1559					relPath = filepath.ToSlash(path)
1560				}
1561				relPath = filepath.ToSlash(filepath.Clean(relPath))
1562	
1563				base, err := gitStageBlob(cmd.Context(), repoRoot, 1, relPath)
1564				if err != nil {
1565					return err
1566				}
1567				ours, err := gitStageBlob(cmd.Context(), repoRoot, 2, relPath)
1568				if err != nil {
1569					return err
1570				}
1571				theirs, err := gitStageBlob(cmd.Context(), repoRoot, 3, relPath)
1572				if err != nil {
1573					return err
1574				}
1575	
1576				merged, report, err := bead.MergeTrackerConflictJSONL(base, ours, theirs)
1577				if err != nil {
1578					return err
1579				}
1580				outPath := filepath.Join(repoRoot, relPath)
1581				if err := os.MkdirAll(filepath.Dir(outPath), 0o755); err != nil {
1582					return fmt.Errorf("bead merge: mkdir: %w", err)
1583				}
1584				if err := os.WriteFile(outPath, merged, 0o644); err != nil {
1585					return fmt.Errorf("bead merge: write %s: %w", relPath, err)
1586				}
1587	
1588				fmt.Fprintf(cmd.OutOrStdout(), "Merged %s: %d records (%d ours-only, %d theirs-only, %d same-id merged)\n",
1589					relPath, report.TotalRecords, report.PreservedOurs, report.PreservedTheirs, report.MergedRecords)
1590				for _, conflict := range report.ScalarConflicts {
1591					fmt.Fprintf(cmd.OutOrStdout(), "Resolved scalar conflict: %s.%s chose %s (%s)\n",
1592						conflict.ID, conflict.Field, conflict.Choice, conflict.Reason)
1593				}
1594				return nil
1595			},
1596		}
1597		return cmd
1598	}
