1220	func (f *CommandFactory) newAgentReplayCommand() *cobra.Command {
1221		cmd := &cobra.Command{
1222			Use:   "replay <bead-id>",
1223			Short: "Replay a bead with a different agent harness or model",
1224			Long: `Reconstructs the prompt from the bead's linked agent session and re-runs it
1225	with a different harness or model for comparison.
1226	
1227	Examples:
1228	  ddx agent replay ddx-abc123 --harness claude --model claude-opus-4-6
1229	  ddx agent replay ddx-abc123 --harness agent --at-head
1230	  ddx agent replay ddx-abc123 --sandbox`,
1231			Args: cobra.ExactArgs(1),
1232			RunE: func(cmd *cobra.Command, args []string) error {
1233				beadID := args[0]
1234				harness, _ := cmd.Flags().GetString("harness")
1235				model, _ := cmd.Flags().GetString("model")
1236				atHead, _ := cmd.Flags().GetBool("at-head")
1237				sandbox, _ := cmd.Flags().GetBool("sandbox")
1238	
1239				// Get the bead
1240				b, err := f.beadStore().Get(beadID)
1241				if err != nil {
1242					return fmt.Errorf("bead not found: %w", err)
1243				}
1244	
1245				// Extract session ID from bead evidence
1246				sessionID := ""
1247				if b.Extra != nil {
1248					if sid, ok := b.Extra["session_id"]; ok {
1249						sessionID = fmt.Sprint(sid)
1250					}
1251				}
1252	
1253				// Get the prompt - from session or fallback to bead prose
1254				var prompt string
1255				var baseCommit string
1256				if sessionID != "" {
1257					sess := f.resolveAgentSession(sessionID)
1258					if sess != nil {
1259						prompt = sess.Prompt
1260						// Store original metadata for comparison
1261						fmt.Fprintf(cmd.OutOrStdout(), "Replaying from session %s\n", sessionID)
1262						fmt.Fprintf(cmd.OutOrStdout(), "Original: %s with %s\n", sess.Harness, sess.Model)
1263					}
1264				}
1265	
1266				// Fallback to bead prose if no session prompt (title → description → acceptance)
1267				if prompt == "" {
1268					switch {
1269					case b.Title != "":
1270						prompt = b.Title
1271						fmt.Fprintf(cmd.OutOrStdout(), "Note: Using bead title as prompt (baseline session unknown)\n")
1272					case b.Description != "":
1273						prompt = b.Description
1274						fmt.Fprintf(cmd.OutOrStdout(), "Note: Using bead description as prompt (baseline session unknown)\n")
1275					case b.Acceptance != "":
1276						prompt = b.Acceptance
1277						fmt.Fprintf(cmd.OutOrStdout(), "Note: Using bead acceptance criteria as prompt (baseline session unknown)\n")
1278					default:
1279						return fmt.Errorf("no prompt available from session or bead")
1280					}
1281				}
1282	
1283				// Determine base commit
1284				if !atHead {
1285					if b.Extra != nil {
1286						if sha, ok := b.Extra["closing_commit_sha"]; ok && sha != "" {
1287							// Use parent of closing commit
1288							shaStr := fmt.Sprint(sha)
1289							out, err := gitpkg.Command(cmd.Context(), "", "rev-parse", shaStr+"^").Output()
1290							if err == nil {
1291								baseCommit = strings.TrimSpace(string(out))
1292								fmt.Fprintf(cmd.OutOrStdout(), "Base commit: %s (parent of %s)\n", baseCommit, shaStr)
1293							}
1294						}
1295					}
1296				}
1297	
1298				// If no base commit determined, use current HEAD
1299				if baseCommit == "" {
1300					out, err := gitpkg.Command(cmd.Context(), "", "rev-parse", "HEAD").Output()
1301					if err == nil {
1302						baseCommit = strings.TrimSpace(string(out))
1303						fmt.Fprintf(cmd.OutOrStdout(), "Base commit: %s (current HEAD)\n", baseCommit)
1304					}
1305				}
1306	
1307				// Setup workdir for sandbox mode
1308				workDir := ""
1309				if sandbox {
1310					wtName := fmt.Sprintf("replay-%s-%s", beadID, harness)
1311					wtDir, err := resolveWorktree(f.WorkingDir, wtName)
1312					if err != nil {
1313						return fmt.Errorf("sandbox worktree: %w", err)
1314					}
1315					workDir = wtDir
1316					fmt.Fprintf(cmd.OutOrStdout(), "Sandbox: %s\n", workDir)
1317	
1318					// Checkout base commit in worktree
1319					if baseCommit != "" {
1320						gitCmd := gitpkg.Command(cmd.Context(), workDir, "checkout", baseCommit)
1321						if out, err := gitCmd.CombinedOutput(); err != nil {
1322							return fmt.Errorf("checkout %s: %w\n%s", baseCommit, err, string(out))
1323						}
1324					}
1325				}
1326	
1327				fmt.Fprintf(cmd.OutOrStdout(), "\nReplaying with %s", harness)
1328				if model != "" {
1329					fmt.Fprintf(cmd.OutOrStdout(), " (%s)", model)
1330				}
1331				fmt.Fprintln(cmd.OutOrStdout())
1332				fmt.Fprintln(cmd.OutOrStdout(), strings.Repeat("-", 50))
1333	
1334				// Run the agent
1335				rcfg, _ := config.LoadAndResolve(f.WorkingDir, config.CLIOverrides{
1336					Harness: harness,
1337					Model:   model,
1338				})
1339				result, err := agent.RunWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, agent.AgentRunRuntime{
1340					Prompt:  prompt,
1341					WorkDir: workDir,
1342				})
1343				if err != nil {
1344					return fmt.Errorf("agent run failed: %w", err)
1345				}
1346	
1347				// Show results
1348				fmt.Fprintln(cmd.OutOrStdout())
1349				fmt.Fprintln(cmd.OutOrStdout(), strings.Repeat("-", 50))
1350				fmt.Fprintf(cmd.OutOrStdout(), "Exit code: %d\n", result.ExitCode)
1351				fmt.Fprintf(cmd.OutOrStdout(), "Duration: %dms\n", result.DurationMS)
1352				if result.Tokens > 0 {
1353					fmt.Fprintf(cmd.OutOrStdout(), "Tokens: %d\n", result.Tokens)
1354				}
1355				if result.CostUSD > 0 {
1356					fmt.Fprintf(cmd.OutOrStdout(), "Cost: $%.4f\n", result.CostUSD)
1357				}
1358	
1359				// Show diff if sandbox mode
1360				if sandbox && workDir != "" {
1361					fmt.Fprintln(cmd.OutOrStdout())
1362					fmt.Fprintln(cmd.OutOrStdout(), "Changes:")
1363					gitCmd := gitpkg.Command(cmd.Context(), workDir, "diff", "--stat")
1364					out, _ := gitCmd.CombinedOutput()
1365					if len(out) > 0 {
1366						_, _ = cmd.OutOrStderr().Write(out)
1367					} else {
1368						fmt.Fprintln(cmd.OutOrStdout(), "  (no changes)")
1369					}
1370				}
1371	
1372				return nil
1373			},
1374		}
1375	
1376		cmd.Flags().String("harness", "", "Agent harness to use for replay (required)")
1377		cmd.Flags().String("model", "", "Model override for the harness")
1378		cmd.Flags().Bool("at-head", false, "Replay against current HEAD instead of closing commit parent")
1379		cmd.Flags().Bool("sandbox", false, "Run in an isolated git worktree")
1380	
1381		return cmd
1382	}
